text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과 시 공개 릴리스 목표는 금요일 15:00 KST로 한다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "result": "거부됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정은 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자가 지정되지 않았다."
      },
      {
        "topic": "수요일 내부 스트레치 목표를 릴리스 노트에 언급할지 여부",
        "note": "결론이 나지 않았다."
      },
      {
        "topic": "최종 릴리스 승인 권한자",
        "note": "확정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "도윤",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "하라",
      "task": "민준이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 점검한다.",
      "due": null,
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일(가능하면)",
      "status": "미확정",
      "source_certainty": "논의되었으나 담당자 미지정"
    }
  ],
  "followup_note": {
    "next_checks": [
      "민준의 스모크 테스트 재실행 결과와 통과 여부를 확인한다.",
      "스모크 결과 공유 후 하라의 tarball 경로 점검 결과를 확인한다.",
      "도윤의 failure triage note 작성 여부를 확인한다.",
      "README 설치 단계 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 승인 절차가 확정되었는지 확인한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 결정되었는지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "미지정 담당자",
      "명시되지 않은 마감 시각"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정 결정과 제안, 스트레치 목표, 미결 사항을 섞지 않는다.",
    "담당자나 마감이 명시되지 않은 항목은 null 또는 미확정으로 둔다.",
    "수요일 일정은 공개 릴리스 확정이 아니라 내부 스트레치 목표로만 기록한다.",
    "packageName mismatch 무시 제안은 거부된 안으로만 기록한다."
  ]
}
